function parseScenarios(data: string): Scenario[] {
  const scenarios: Scenario[] = [];
  const lines = data.trim().split('\n');
  
  let currentScenario: Partial<Scenario> = {};
  let inQuote = false;
  let currentField = '';
  let fieldIndex = 0;
  
  // Custom parser to handle quoted multi-line fields
  for (let i = 0; i < data.length; i++) {
    const char = data[i];
    const nextChar = data[i + 1];
    
    if (char === '"') {
      inQuote = !inQuote;
    } else if (char === '\t' && !inQuote) {
      // End of field
      assignField(currentScenario, fieldIndex, currentField);
      currentField = '';
      fieldIndex++;
    } else if (char === '\n' && !inQuote) {
      // End of row
      assignField(currentScenario, fieldIndex, currentField);
      if (currentScenario.useCaseId) {
        // Ensure required fields have defaults
        if (!currentScenario.useCaseSourceId) currentScenario.useCaseSourceId = currentScenario.useCaseId || '';
        scenarios.push(currentScenario as Scenario);
      }
      currentScenario = {};
      currentField = '';
      fieldIndex = 0;
    } else {
      currentField += char;
    }
  }
  
  // Handle last field/row
  if (currentField || fieldIndex > 0) {
    assignField(currentScenario, fieldIndex, currentField);
    if (currentScenario.useCaseId) {
      if (!currentScenario.useCaseSourceId) currentScenario.useCaseSourceId = currentScenario.useCaseId || '';
      scenarios.push(currentScenario as Scenario);
    }
  }
  
  return scenarios;
}

function assignField(scenario: Partial<Scenario>, index: number, value: string) {
  // Clean up quotes if wrapped
  let cleanValue = value.trim();
  if (cleanValue.startsWith('"') && cleanValue.endsWith('"')) {
    cleanValue = cleanValue.substring(1, cleanValue.length - 1).replace(/""/g, '"');
  }
  
  switch (index) {
    case 0: scenario.useCaseId = cleanValue; break;
    case 1: scenario.scenarioId = cleanValue; break;
    case 2: scenario.sector = cleanValue; break;
    case 3: scenario.categoryOfUseCase = cleanValue; break;
    case 4: scenario.groupName = cleanValue; break;
    case 5: scenario.scenarioTitle = cleanValue; break;
    case 6: scenario.scenarioDescription = cleanValue; break;
    case 7: scenario.scenarioNarrative = cleanValue; break;
    case 8: scenario.redTeamingObjective = cleanValue; break;
    case 9: scenario.usersDirect = cleanValue; break;
    case 10: scenario.usersIndirect = cleanValue; break;
    case 11: scenario.intendedOutcomes = cleanValue; break;
    case 12: scenario.positiveImpactsBenefits = cleanValue; break;
    case 13: scenario.negativeImpactsRisk = cleanValue; break;
    case 14: scenario.kpisAndMetrics = cleanValue; break;
    case 15: scenario.useCaseSourceId = cleanValue; break;
  }
}

export const staticScenarios = parseScenarios(rawData);
